{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A parcel movement unit with a pickup address, delivery address, weight, and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, InTransit, Delivered." },
      { "term": "Weight Bracket", "definition": "A pricing classification tier determined by shipment weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." },
      { "term": "Final State", "definition": "A terminal lifecycle state from which no further transitions are permitted. Delivered is a final state." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — it cannot be routed, priced, or fulfilled. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a missing or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions follow a strict forward-only lifecycle: Pending → InTransit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Backward transitions (e.g., InTransit → Pending) would corrupt audit trails, trigger incorrect billing events, and misrepresent physical reality. State integrity constraint.",
      "testable_assertion": "A shipment in InTransit state must reject any transition to Pending. The only valid transition from InTransit is to Delivered."
    },
    {
      "id": "BR-3",
      "rule": "A Delivered shipment is in a final (terminal) state — no further state changes are allowed.",
      "invariant": true,
      "invariant_justification": "Delivered represents a completed physical handoff. Allowing state changes after delivery would break billing finality, reporting accuracy, and chain-of-custody integrity.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment (to Pending, InTransit, or any other state) must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound is a physical/operational constraint (vehicle capacity, handling equipment). Violating either corrupts pricing and operational planning.",
      "testable_assertion": "Weight values of 0, negative numbers, or values exceeding 1000 kg must be rejected at creation and at any update point."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = weight > 0 and weight ≤ 10 kg; Heavy = weight > 10 and weight ≤ 50 kg; Freight = weight > 50 and weight ≤ 1000 kg.",
      "invariant": false,
      "invariant_justification": "Bracket thresholds are a pricing policy. A VP could adjust these boundaries (e.g., change Heavy to 15–60 kg) without corrupting system integrity.",
      "testable_assertion": "A 10 kg shipment is classified as Standard. A 10.01 kg shipment is classified as Heavy. A 50 kg shipment is classified as Heavy. A 50.01 kg shipment is classified as Freight."
    },
    {
      "id": "BR-6",
      "rule": "A newly created shipment starts in Pending state.",
      "invariant": true,
      "invariant_justification": "Creating a shipment directly in InTransit or Delivered would bypass pickup logistics and audit requirements. Initial state consistency is a data integrity constraint.",
      "testable_assertion": "After successful creation, a shipment's state must be Pending."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address, delivery address, and weight of 5 kg",
      "when": "A shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A missing pickup address",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A missing delivery address",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment is moved to InTransit",
      "then": "The state transition succeeds and the shipment is now InTransit"
    },
    {
      "id": "AC-5",
      "given": "A shipment in InTransit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The transition is rejected with an error indicating backward transitions are not allowed"
    },
    {
      "id": "AC-6",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted",
      "then": "The transition is rejected with an error indicating Delivered is a final state"
    },
    {
      "id": "AC-7",
      "given": "A weight of 0 kg",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with an error indicating weight must be positive"
    },
    {
      "id": "AC-8",
      "given": "A weight of -1 kg",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with an error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A weight of 1001 kg",
      "when": "A shipment creation is attempted",
      "then": "The creation is rejected with an error indicating weight cannot exceed 1000 kg"
    },
    {
      "id": "AC-10",
      "given": "A shipment with weight of 10 kg",
      "when": "The weight bracket is calculated",
      "then": "The bracket is Standard"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight of 10.01 kg",
      "when": "The weight bracket is calculated",
      "then": "The bracket is Heavy"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight of 50 kg",
      "when": "The weight bracket is calculated",
      "then": "The bracket is Heavy"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight of 50.01 kg",
      "when": "The weight bracket is calculated",
      "then": "The bracket is Freight"
    },
    {
      "id": "AC-14",
      "given": "A shipment in InTransit state",
      "when": "The shipment is moved to Delivered",
      "then": "The state transition succeeds and the shipment is now in the final Delivered state"
    },
    {
      "id": "AC-15",
      "given": "A shipment with weight of exactly 1000 kg",
      "when": "A shipment creation is attempted",
      "then": "The creation succeeds and the weight bracket is Freight"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (boundary between Standard and Heavy)", "expected_behavior": "Classified as Standard — the bracket is inclusive of the upper bound at 10 kg." },
    { "scenario": "Weight is exactly 50 kg (boundary between Heavy and Freight)", "expected_behavior": "Classified as Heavy — the bracket is inclusive of the upper bound at 50 kg." },
    { "scenario": "Weight is exactly 1000 kg (maximum allowed)", "expected_behavior": "Accepted and classified as Freight." },
    { "scenario": "Weight is a very small positive number (e.g., 0.001 kg)", "expected_behavior": "Accepted and classified as Standard. The spec says positive — no minimum threshold beyond > 0 is stated." },
    { "scenario": "Attempt to transition directly from Pending to Delivered (skipping InTransit)", "expected_behavior": "Ambiguous — spec does not explicitly allow or forbid skipping InTransit. Escalated." },
    { "scenario": "Pickup and delivery addresses are the same location", "expected_behavior": "Ambiguous — spec does not prohibit same-origin-destination shipments. Likely a data quality issue but not explicitly ruled out." },
    { "scenario": "Delivered shipment attempts to transition to Delivered again (idempotent re-delivery)", "expected_behavior": "Rejected — Delivered is final; no state change is permitted, including self-transitions." },
    { "scenario": "Weight provided with excessive decimal precision (e.g., 10.000000001 kg)", "expected_behavior": "Implementation must decide rounding strategy, but the bracket boundary logic must be deterministic. Suggest defining a precision (e.g., 2 decimal places)." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect boundaries or misclassification leads to revenue leakage (undercharging) or customer disputes (overcharging). The Standard/Heavy/Freight tiers likely map to significantly different rate cards.",
    "operational": "State machine enforcement ensures dispatchers and warehouse staff see accurate shipment status. Allowing backward transitions would create ghost pickups, double dispatches, and unreliable ETAs. The 1000 kg cap ensures compatibility with fleet vehicle capacities and loading equipment.",
    "user": "Shippers and recipients depend on accurate state progression for tracking visibility. Final-state enforcement on Delivered gives confidence that delivery records are immutable and trustworthy for proof-of-delivery disputes.",
    "risk": "Primary risk is bracket boundary ambiguity — a single kg misclassification at high volumes compounds into significant revenue impact. Secondary risk is the undefined Pending → Delivered skip path, which if accidentally allowed could bypass pickup scan events.",
    "stakeholders_affected": [
      { "group": "Shippers (senders)", "impact": "Must provide valid addresses and weight. Pricing is determined by weight bracket — transparency here affects trust and satisfaction." },
      { "group": "Recipients", "impact": "Depend on accurate state tracking for delivery expectations. Immutable Delivered state protects against disputes." },
      { "group": "Operations / Dispatch", "impact": "State machine correctness ensures dispatch workflows are reliable. No backward transitions means no phantom re-pickups." },
      { "group": "Finance / Billing", "impact": "Weight bracket accuracy directly impacts invoicing correctness and revenue recognition." },
      { "group": "Customer Support", "impact": "Clear, immutable state history reduces dispute resolution complexity." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is concise and mostly unambiguous for what it covers. State lifecycle rules and weight constraints are clear. However, several domain-relevant questions are left unaddressed: whether Pending → Delivered is allowed (skipping InTransit), whether weight can be modified after creation, what constitutes a valid address, and whether there are additional states (e.g., Cancelled, Failed). The bracket boundaries are clear but the boundary inclusivity (≤ vs <) at 10 and 50 kg had to be inferred from 'X to Y' phrasing.",
    "high_confidence_areas": [
      "Weight must be positive and ≤ 1000 kg",
      "Delivered is a terminal/final state",
      "InTransit cannot revert to Pending",
      "Both addresses required at creation"
    ],
    "low_confidence_areas": [
      "Whether Pending → Delivered direct transition is valid or must go through InTransit",
      "Bracket boundary inclusivity at exactly 10 kg and 50 kg (inferred, not explicit)",
      "Whether weight can be updated after shipment creation",
      "Address validation rules beyond mere presence",
      "Whether additional states exist (Cancelled, Failed, ReturnToSender)"
    ],
    "assumptions": [
      "Bracket boundaries are upper-inclusive: 0–10 means (0, 10], 10–50 means (10, 50], >50 means (50, 1000]",
      "New shipments always start in Pending state (implied but not explicitly stated)",
      "Weight is set at creation and the spec does not address mutability",
      "No other states exist beyond Pending, InTransit, and Delivered"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether a shipment can transition directly from Pending to Delivered, skipping InTransit. In real logistics, this could represent local/in-store pickups or instant deliveries. If forbidden, we need explicit validation; if allowed, it changes the state machine shape.",
      "affected_stakeholders": ["Operations / Dispatch", "Finance / Billing", "Customer Support"],
      "options": [
        "A: Enforce strict linear progression (Pending → InTransit → Delivered only)",
        "B: Allow Pending → Delivered as a valid shortcut for edge-case fulfillment scenarios"
      ],
      "recommendation": "Option A — enforce strict linear progression. In logistics, InTransit represents the physical movement and scan event chain. Skipping it loses chain-of-custody data. If instant-delivery use cases arise, they should still pass through InTransit momentarily."
    },
    {
      "type": "ambiguity",
      "description": "Bracket boundary inclusivity is not explicitly stated. '0-10 kg is standard' could mean ≤10 or <10. This matters for pricing at exactly 10 kg and 50 kg.",
      "affected_stakeholders": ["Shippers (senders)", "Finance / Billing"],
      "options": [
        "A: Upper-inclusive brackets — Standard: (0, 10], Heavy: (10, 50], Freight: (50, 1000]",
        "B: Upper-exclusive brackets — Standard: (0, 10), Heavy: [10, 50), Freight: [50, 1000]"
      ],
      "recommendation": "Option A — upper-inclusive is the most natural reading of '0-10 kg' and favors the customer at boundary points (they get the cheaper tier). This reduces billing disputes."
    },
    {
      "type": "missing_context",
      "description": "The spec does not address shipment cancellation or failure states. Real logistics requires handling lost parcels, refused deliveries, and sender-initiated cancellations. Without these, the state machine is incomplete for production use.",
      "affected_stakeholders": ["Operations / Dispatch", "Customer Support", "Shippers (senders)", "Recipients"],
      "options": [
        "A: Add Cancelled state (reachable from Pending and InTransit) and Failed state (reachable from InTransit)",
        "B: Defer additional states — implement only the three described states now"
      ],
      "recommendation": "Option B for initial implementation, but flag that Cancelled and Failed states will be needed before production launch. Build the state machine to be extensible."
    }
  ],

  "rejection_reasons": []
}

